def brainfuck_interpreter(code, inp=""):
    tape = [0]
    ptr = 0
    ip = 0
    inp_i = 0
    out = []

    # Precompute matching brackets
    stack = []
    jumps = {}
    for i, c in enumerate(code):
        if c == "[":
            stack.append(i)
        elif c == "]":
            j = stack.pop()
            jumps[i] = j
            jumps[j] = i

    while ip < len(code):
        c = code[ip]

        if c == ">":
            ptr += 1
            if ptr == len(tape):
                tape.append(0)
        elif c == "<":
            ptr = max(0, ptr - 1)
        elif c == "+":
            tape[ptr] = (tape[ptr] + 1) % 256
        elif c == "-":
            tape[ptr] = (tape[ptr] - 1) % 256
        elif c == ".":
            out.append(chr(tape[ptr]))
        elif c == ",":
            tape[ptr] = ord(inp[inp_i]) if inp_i < len(inp) else 0
            inp_i += 1
        elif c == "[" and tape[ptr] == 0:
            ip = jumps[ip]
        elif c == "]" and tape[ptr] != 0:
            ip = jumps[ip]

        ip += 1

    return "".join(out)
